   1→import { useEffect, useMemo, useRef, useState } from "react";
   2→import Konva from "konva";
   3→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
   4→import { BarLoader } from "react-spinners";
   5→import { useQueryClient } from "@tanstack/react-query";
   6→import { saveJournal, saveJournalImage } from "../../../../API/Api";
   7→import { useAuth } from "../../../Context/useAuth";
   8→import { parseCanvasDoc } from "../../../utils/canvasDoc";
   9→import styles from "./CanvasEditor.module.css";
  10→import "./canvas.css";
  11→
  12→const FONT_BRUSHES = {
  13→    serif: {label: "Typewriter", fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal", preview: "Ink Tape"},
  14→    handwritten: {label: "Brush Script", fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal", preview: "Wild Brush"},
  15→    bold: {label: "Street Bold", fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold", preview: "Tagline"},
  16→    serifDisplay: {label: "Poster Serif", fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal", preview: "Headline"}
  17→};
  18→
  19→const FONT_STYLE_MAP = {
  20→    serif: "serif",
  21→    handwritten: "handwritten",
  22→    bold: "bold",
  23→    mono: "serif",
  24→    serifDisplay: "serifDisplay"
  25→};
  26→
  27→const GRID_SIZE = 24;
  28→const CANVAS_MAX_WIDTH = 560;
  29→const MOBILE_BREAKPOINT = 820;
  30→const MIN_VIEWPORT_SCALE = 0.85;
  31→const MAX_VIEWPORT_SCALE = 3;
  32→const OBJECT_LIFT_MULTIPLIER = 1.03;
  33→
  34→const COLOR_PALETTES = [
  35→    {label: "Pastels", colors: ["#f8c8dc", "#f9e2af", "#b7e4c7", "#bde0fe", "#d7c3ff"]},
  36→    {label: "Earth", colors: ["#8c5e3c", "#b7794b", "#5a6d4d", "#4d6f75", "#2f3e46"]},
  37→    {label: "Neon", colors: ["#ff2d55", "#ff7a00", "#f7ff00", "#00e5ff", "#8a2be2"]}
  38→];
  39→
  40→const DEFAULT_DOODLE_COLOR = COLOR_PALETTES[2].colors[0];
  41→
  42→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  43→const createId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  44→
  45→const sanitizeNormalizedPoints = (rawPoints) => {
  46→    if(!Array.isArray(rawPoints)){
  47→        return [];
  48→    }
  49→
  50→    const numericPoints = rawPoints
  51→        .map((point) => Number(point))
  52→        .filter((point) => !Number.isNaN(point))
  53→        .map((point) => clamp(point, 0, 1));
  54→
  55→    if(numericPoints.length < 2){
  56→        return [];
  57→    }
  58→
  59→    return numericPoints.length % 2 === 0 ? numericPoints : numericPoints.slice(0, -1);
  60→};
  61→
  62→const getStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
  63→
  64→const getLegacyFontStyle = (fontStyle) => {
  65→    if(fontStyle === "mono"){
  66→        return "serif";
  67→    }
  68→    return FONT_STYLE_MAP[fontStyle] ? fontStyle : "serif";
  69→};
  70→
  71→const getSnippetMetrics = (snippet, stageWidth) => {
  72→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  73→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
  74→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
  75→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  76→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  77→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
  78→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
  79→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
  80→    return {width: estimatedWidth, height, fontSize};
  81→};
  82→
  83→const constrainViewport = (candidate, stageWidth, stageHeight) => {
  84→    const scale = clamp(candidate?.scale || 1, MIN_VIEWPORT_SCALE, MAX_VIEWPORT_SCALE);
  85→    const scaledWidth = stageWidth * scale;
  86→    const scaledHeight = stageHeight * scale;
  87→    let minX = Math.min(0, stageWidth - scaledWidth);
  88→    let maxX = 0;
  89→    let minY = Math.min(0, stageHeight - scaledHeight);
  90→    let maxY = 0;
  91→
  92→    if(scaledWidth <= stageWidth){
  93→        const centeredX = (stageWidth - scaledWidth) / 2;
  94→        minX = centeredX;
  95→        maxX = centeredX;
  96→    }
  97→    if(scaledHeight <= stageHeight){
  98→        const centeredY = (stageHeight - scaledHeight) / 2;
  99→        minY = centeredY;
 100→        maxY = centeredY;
 101→    }
 102→
 103→    return {
 104→        scale,
 105→        x: clamp(candidate?.x || 0, minX, maxX),
 106→        y: clamp(candidate?.y || 0, minY, maxY)
 107→    };
 108→};
 109→
 110→const getTouchGeometry = (nativeEvent, stage) => {
 111→    const touches = nativeEvent?.touches;
 112→    if(!stage || !touches || touches.length < 2){
 113→        return null;
 114→    }
 115→
 116→    const bounds = stage.container()?.getBoundingClientRect();
 117→    if(!bounds){
 118→        return null;
 119→    }
 120→
 121→    const first = touches[0];
 122→    const second = touches[1];
 123→    const firstPoint = {x: first.clientX - bounds.left, y: first.clientY - bounds.top};
 124→    const secondPoint = {x: second.clientX - bounds.left, y: second.clientY - bounds.top};
 125→
 126→    return {
 127→        center: {x: (firstPoint.x + secondPoint.x) / 2, y: (firstPoint.y + secondPoint.y) / 2},
 128→        distance: Math.hypot(secondPoint.x - firstPoint.x, secondPoint.y - firstPoint.y)
 129→    };
 130→};
 131→
 132→const useLoadedImage = (src) => {
 133→    const [image, setImage] = useState(null);
 134→
 135→    useEffect(() => {
 136→        if(!src){
 137→            setImage(null);
 138→            return;
 139→        }
 140→
 141→        const img = new window.Image();
 142→        img.crossOrigin = "anonymous";
 143→        img.onload = () => setImage(img);
 144→        img.onerror = () => setImage(null);
 145→        img.src = src;
 146→
 147→        return () => {
 148→            img.onload = null;
 149→            img.onerror = null;
 150→        };
 151→    }, [src]);
 152→
 153→    return image;
 154→};
 155→
 156→const CanvasImageNode = ({
 157→    canvasImage,
 158→    stageWidth,
 159→    stageHeight,
 160→    isSelected,
 161→    isDragging,
 162→    onSelect,
 163→    onDragStart,
 164→    onDragEnd,
 165→    canInteract,
 166→    preventTouchDefault
 167→}) => {
 168→    const loadedImage = useLoadedImage(canvasImage?.src);
 169→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 170→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 171→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 172→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 173→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 174→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 175→
 176→    return (
 177→        <>
 178→            <KonvaImage
 179→                x={x}
 180→                y={y}
 181→                width={objectWidth}
 182→                height={objectHeight}
 183→                image={loadedImage}
 184→                draggable={canInteract}
 185→                rotation={canvasImage?.rotation || 0}
 186→                scaleX={baseScaleX * liftMultiplier}
 187→                scaleY={liftMultiplier}
 188→                shadowColor="rgba(0,0,0,0.3)"
 189→                shadowBlur={isSelected || isDragging ? 16 : 8}
 190→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 191→                preventDefault={preventTouchDefault}
 192→                onClick={canInteract ? onSelect : undefined}
 193→                onTap={canInteract ? onSelect : undefined}
 194→                onDragStart={onDragStart}
 195→                onDragEnd={onDragEnd}
 196→            />
 197→            {isSelected && (
 198→                <Rect
 199→                    x={x}
 200→                    y={y}
 201→                    width={objectWidth}
 202→                    height={objectHeight}
 203→                    stroke="#68d391"
 204→                    strokeWidth={1.7}
 205→                    dash={[6, 4]}
 206→                    rotation={canvasImage?.rotation || 0}
 207→                    listening={false}
 208→                />
 209→            )}
 210→        </>
 211→    );
 212→};
