 214→const CanvasEditor = ({title, onCloseOnSave, addUploadedImagePath, initialCanvasDoc = null, remixSource = null}) => {
 215→    const {session, user} = useAuth();
 216→    const queryClient = useQueryClient();
 217→    const shellRef = useRef(null);
 218→    const stageRef = useRef(null);
 219→    const hasHydratedInitialDocRef = useRef(false);
 220→    const snippetInputRef = useRef(null);
 221→    const doodlePointsRef = useRef([]);
 222→    const viewportRef = useRef({scale: 1, x: 0, y: 0});
 223→    const pinchStateRef = useRef({isActive: false, lastDistance: 0, lastCenter: null});
 224→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 225→
 226→    const [activeTool, setActiveTool] = useState("select");
 227→    const [isSnippetComposerOpen, setIsSnippetComposerOpen] = useState(false);
 228→    const [snippetInput, setSnippetInput] = useState("");
 229→    const [selectedObject, setSelectedObject] = useState(null);
 230→    const [draggingObject, setDraggingObject] = useState(null);
 231→    const [isSending, setIsSending] = useState(false);
 232→    const [isUploadingImage, setIsUploadingImage] = useState(false);
 233→    const [doodleColor, setDoodleColor] = useState(DEFAULT_DOODLE_COLOR);
 234→    const [doodleSize, setDoodleSize] = useState(2.8);
 235→    const [isDrawing, setIsDrawing] = useState(false);
 236→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 237→    const [canvasMeta, setCanvasMeta] = useState({
 238→        aspectRatio: "1:1",
 239→        gridEnabled: true,
 240→        snapEnabled: true,
 241→        theme: "light"
 242→    });
 243→    const [snippets, setSnippets] = useState([]);
 244→    const [images, setImages] = useState([]);
 245→    const [doodles, setDoodles] = useState([]);
 246→    const [viewport, setViewport] = useState({scale: 1, x: 0, y: 0});
 247→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 248→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 249→    const [isDoodleDockMinimized, setIsDoodleDockMinimized] = useState(false);
 250→
 251→    const updateSnippet = (snippetId, updater) => {
 252→        setSnippets((prev) => prev.map((snippet) => {
 253→            if(snippet.id !== snippetId){
 254→                return snippet;
 255→            }
 256→            const nextValue = typeof updater === "function" ? updater(snippet) : updater;
 257→            return {...snippet, ...nextValue};
 258→        }));
 259→    };
 260→
 261→    const updateImage = (imageId, updater) => {
 262→        setImages((prev) => prev.map((image) => {
 263→            if(image.id !== imageId){
 264→                return image;
 265→            }
 266→            const nextValue = typeof updater === "function" ? updater(image) : updater;
 267→            return {...image, ...nextValue};
 268→        }));
 269→    };
 270→
 271→    useEffect(() => {
 272→        if(hasHydratedInitialDocRef.current || !initialCanvasDoc){
 273→            return;
 274→        }
 275→
 276→        const parsedDoc = parseCanvasDoc(initialCanvasDoc);
 277→        setCanvasMeta((prev) => ({
 278→            ...prev,
 279→            aspectRatio: parsedDoc?.meta?.aspectRatio === "4:5" ? "4:5" : "1:1",
 280→            gridEnabled: Boolean(parsedDoc?.meta?.gridEnabled),
 281→            theme: parsedDoc?.meta?.theme === "dark" ? "dark" : "light"
 282→        }));
 283→        setSnippets((parsedDoc?.snippets || []).map((snippet) => ({
 284→            ...snippet,
 285→            id: snippet.id || createId("snippet"),
 286→            fontStyle: getLegacyFontStyle(snippet.fontStyle),
 287→            zIndex: Number.isFinite(snippet?.zIndex) ? snippet.zIndex : 0
 288→        })));
 289→        setImages((parsedDoc?.images || []).map((image) => ({
 290→            ...image,
 291→            id: image.id || createId("image"),
 292→            zIndex: Number.isFinite(image?.zIndex) ? image.zIndex : 0
 293→        })));
 294→        setDoodles((parsedDoc?.doodles || []).map((doodle) => ({
 295→            ...doodle,
 296→            id: doodle.id || createId("doodle"),
 297→            points: sanitizeNormalizedPoints(doodle.points)
 298→        })));
 299→        hasHydratedInitialDocRef.current = true;
 300→    }, [initialCanvasDoc]);
 301→
 302→    useEffect(() => {
 303→        const getContentWidth = () => {
 304→            const element = shellRef.current;
 305→            if(!element){
 306→                return CANVAS_MAX_WIDTH;
 307→            }
 308→            const computedStyle = getComputedStyle(element);
 309→            const paddingLeft = parseFloat(computedStyle.paddingLeft) || 0;
 310→            const paddingRight = parseFloat(computedStyle.paddingRight) || 0;
 311→            return Math.max(0, element.clientWidth - paddingLeft - paddingRight);
 312→        };
 313→
 314→        const updateShellWidth = () => {
 315→            setShellWidth(getContentWidth());
 316→        };
 317→
 318→        updateShellWidth();
 319→        window.addEventListener("resize", updateShellWidth);
 320→
 321→        let resizeObserver = null;
 322→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 323→            resizeObserver = new ResizeObserver(updateShellWidth);
 324→            resizeObserver.observe(shellRef.current);
 325→        }
 326→
 327→        return () => {
 328→            window.removeEventListener("resize", updateShellWidth);
 329→            if(resizeObserver){
 330→                resizeObserver.disconnect();
 331→            }
 332→        };
 333→    }, []);
 334→
 335→    useEffect(() => {
 336→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 337→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 338→        syncViewport();
 339→
 340→        if(typeof mediaQuery.addEventListener === "function"){
 341→            mediaQuery.addEventListener("change", syncViewport);
 342→            return () => mediaQuery.removeEventListener("change", syncViewport);
 343→        }
 344→
 345→        mediaQuery.addListener(syncViewport);
 346→        return () => mediaQuery.removeListener(syncViewport);
 347→    }, []);
 348→
 349→    useEffect(() => {
 350→        if(isMobileViewport){
 351→            setIsMobileDockOpen(false);
 352→            return;
 353→        }
 354→        setIsMobileDockOpen(true);
 355→    }, [isMobileViewport]);
 356→
 357→    useEffect(() => {
 358→        if(!isSnippetComposerOpen){
 359→            return;
 360→        }
 361→        const frame = window.requestAnimationFrame(() => snippetInputRef.current?.focus());
 362→        return () => window.cancelAnimationFrame(frame);
 363→    }, [isSnippetComposerOpen]);
 364→
 365→    useEffect(() => {
 366→        if(activeTool !== "doodle"){
 367→            doodlePointsRef.current = [];
 368→            setCurrentDoodlePoints([]);
 369→            setIsDrawing(false);
 370→            setIsDoodleDockMinimized(false);
 371→        }
 372→    }, [activeTool]);
 373→
 374→    const viewportWidth = useMemo(() => Math.max(280, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 375→    const viewportHeight = getStageHeight(viewportWidth, canvasMeta.aspectRatio);
 376→    const stageWidth = CANVAS_MAX_WIDTH;
 377→    const stageHeight = getStageHeight(stageWidth, canvasMeta.aspectRatio);
 378→    const fitScale = viewportWidth > 0 ? viewportWidth / stageWidth : 1;
 379→    const fitOffsetX = (viewportWidth - stageWidth * fitScale) / 2;
 380→    const fitOffsetY = (viewportHeight - stageHeight * fitScale) / 2;
 381→
 382→    const updateViewport = (updater) => {
 383→        setViewport((prev) => {
 384→            const nextValue = typeof updater === "function" ? updater(prev) : updater;
 385→            const constrained = constrainViewport(nextValue, viewportWidth, viewportHeight);
 386→            viewportRef.current = constrained;
 387→            return constrained;
 388→        });
 389→    };
 390→
 391→    useEffect(() => {
 392→        viewportRef.current = viewport;
 393→    }, [viewport]);
 394→
 395→    useEffect(() => {
 396→        setViewport((prev) => constrainViewport(prev, viewportWidth, viewportHeight));
 397→    }, [viewportWidth, viewportHeight]);
 398→
 399→    useEffect(() => {
 400→        const safePixelRatio = clamp(window.devicePixelRatio || 1, 1, 2.5);
