  67→const sortByCreatedAt = (a, b) => {
  68→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  69→    if(byDate !== 0){
  70→        return byDate;
  71→    }
  72→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  73→};
  74→const sanitizeNormalizedPoints = (rawPoints) => {
  75→    if(!Array.isArray(rawPoints)){
  76→        return [];
  77→    }
  78→
  79→    const numericPoints = rawPoints
  80→        .map((point) => Number(point))
  81→        .filter((point) => !Number.isNaN(point))
  82→        .map((point) => clamp(point, 0, 1));
  83→
  84→    if(numericPoints.length < 2){
  85→        return [];
  86→    }
  87→
  88→    return numericPoints.length % 2 === 0
  89→        ? numericPoints
  90→        : numericPoints.slice(0, -1);
  91→};
  92→const getNameInitial = (name) => {
  93→    const normalizedName = typeof name === "string" ? name.trim() : "";
  94→    return normalizedName ? normalizedName.slice(0, 1).toUpperCase() : "?";
  95→};
  96→
  97→const getStageHeight = (width, aspectRatio) => {
  98→    if(aspectRatio === "4:5"){
  99→        return Math.round(width * 1.25);
 100→    }
 101→    return width;
 102→};
