 104→const getLegacyFontStyle = (fontStyle) => {
 105→    if(fontStyle === "mono"){
 106→        return "serif";
 107→    }
 108→    return FONT_STYLE_MAP[fontStyle] ? fontStyle : "serif";
 109→};
