 124→const useLoadedImage = (src) => {
 125→    const [image, setImage] = useState(null);
 126→
 127→    useEffect(() => {
 128→        if(!src){
 129→            setImage(null);
 130→            return;
 131→        }
 132→
 133→        const img = new window.Image();
 134→        img.crossOrigin = "anonymous";
 135→        img.onload = () => setImage(img);
 136→        img.onerror = () => setImage(null);
 137→        img.src = src;
 138→
 139→        return () => {
 140→            img.onload = null;
 141→            img.onerror = null;
 142→        };
 143→    }, [src]);
 144→
 145→    return image;
 146→};
